/*!
 * YouthTrack Chart Engine v1.0 - Chart.js 4.x compatible API
 * Implements: bar, line, doughnut, pie, polarArea charts
 */
(function(global){
'use strict';

const DEFAULTS = {
  font: { family: "'DM Sans', sans-serif", size: 12 },
  color: '#5a7265',
  plugins: {
    tooltip: { backgroundColor:'#0b2e25', titleColor:'#fff', bodyColor:'#d4f5e2', cornerRadius:8, padding:10 },
    legend:  { labels:{ usePointStyle:true, pointStyleWidth:10 } }
  }
};

function hexToRgba(hex, a) {
  hex = hex.replace('#','');
  if (hex.length === 3) hex = hex.split('').map(c=>c+c).join('');
  const r=parseInt(hex.slice(0,2),16), g=parseInt(hex.slice(2,4),16), b=parseInt(hex.slice(4,6),16);
  return `rgba(${r},${g},${b},${a})`;
}

function parseColor(c) {
  if (!c) return '#cccccc';
  if (Array.isArray(c)) return c;
  return c;
}

function getColor(colors, i) {
  if (Array.isArray(colors)) return colors[i % colors.length];
  return colors;
}

class Chart {
  constructor(canvas, config) {
    if (typeof canvas === 'string') canvas = document.getElementById(canvas);
    this.canvas = canvas;
    this.ctx    = canvas.getContext('2d');
    this.config = config;
    this.type   = config.type;
    this.data   = config.data;
    this.options= config.options || {};
    this._merge(this.options, DEFAULTS);
    this._instances = this._instances || [];
    this._resize();
    this._draw();
    this._resizeObs = new ResizeObserver(() => { this._resize(); this._draw(); });
    this._resizeObs.observe(canvas.parentElement || canvas);
  }

  _merge(target, source) { /* shallow */ }

  _resize() {
    const parent = this.canvas.parentElement;
    if (parent) {
      this.canvas.width  = parent.clientWidth  || 400;
      this.canvas.height = parent.clientHeight || 260;
    }
  }

  _draw() {
    const ctx = this.ctx;
    const W   = this.canvas.width;
    const H   = this.canvas.height;
    ctx.clearRect(0, 0, W, H);
    ctx.font = `${DEFAULTS.font.size}px ${DEFAULTS.font.family}`;

    const type = this.type;
    if      (type === 'bar')       this._drawBar(W, H);
    else if (type === 'line')      this._drawLine(W, H);
    else if (type === 'doughnut')  this._drawPie(W, H, true);
    else if (type === 'pie')       this._drawPie(W, H, false);
    else if (type === 'polarArea') this._drawPolar(W, H);
    else                           this._drawBar(W, H);

    this._drawLegend(W, H);
    this._setupTooltip();
  }

  _getLabels()  { return this.data.labels || []; }
  _getDatasets(){ return this.data.datasets || []; }
  _getDS(i)     { return this._getDatasets()[i] || {}; }
  _getValues(i) { return (this._getDS(i).data || []); }

  _drawBar(W, H) {
    const ctx      = this.ctx;
    const labels   = this._getLabels();
    const datasets = this._getDatasets();
    const isH      = this.options.indexAxis === 'y';
    const padL = isH ? 150 : 40, padR = 20, padT = 20, padB = isH ? 40 : 60;
    const chartW = W - padL - padR;
    const chartH = H - padT - padB;

    // Find max value
    let maxVal = 0;
    datasets.forEach(ds => ds.data.forEach(v => { if (v > maxVal) maxVal = v; }));
    maxVal = maxVal || 1;

    const n     = labels.length;
    const grpW  = (isH ? chartH : chartW) / Math.max(n, 1);
    const barW  = Math.max(4, grpW * 0.6 / datasets.length);
    const gap   = (grpW - barW * datasets.length) / 2;
    const steps = 5;

    ctx.fillStyle = DEFAULTS.color;
    ctx.textAlign = isH ? 'right' : 'center';
    ctx.textBaseline = isH ? 'middle' : 'top';
    ctx.font = `11px ${DEFAULTS.font.family}`;

    // Grid lines & axis labels
    ctx.strokeStyle = '#e4eae6';
    ctx.lineWidth   = 1;
    for (let s = 0; s <= steps; s++) {
      const val = (maxVal / steps) * s;
      if (isH) {
        const x = padL + (val / maxVal) * chartW;
        ctx.beginPath(); ctx.moveTo(x, padT); ctx.lineTo(x, padT + chartH); ctx.stroke();
        ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'center'; ctx.textBaseline = 'top';
        ctx.fillText(Math.round(val), x, padT + chartH + 4);
      } else {
        const y = padT + chartH - (val / maxVal) * chartH;
        ctx.beginPath(); ctx.moveTo(padL, y); ctx.lineTo(padL + chartW, y); ctx.stroke();
        ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
        ctx.fillText(Math.round(val), padL - 6, y);
      }
    }

    // Bars
    datasets.forEach((ds, di) => {
      const colors = ds.backgroundColor;
      ds.data.forEach((val, i) => {
        const color = getColor(colors, i);
        const bLen  = (val / maxVal) * (isH ? chartW : chartH);
        const radius= ds.borderRadius || 0;

        if (isH) {
          const y = padT + i * grpW + gap + di * barW;
          this._roundRect(ctx, padL, y, Math.max(0, bLen), barW, radius, color);
          // y-axis label
          ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
          ctx.font = `11px ${DEFAULTS.font.family}`;
          ctx.fillText(labels[i] || '', padL - 6, y + barW / 2);
        } else {
          const x = padL + i * grpW + gap + di * barW;
          const y = padT + chartH - Math.max(0, bLen);
          this._roundRect(ctx, x, y, barW, Math.max(0, bLen), radius, color);
          // x-axis label
          ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'center'; ctx.textBaseline = 'top';
          ctx.font = `10px ${DEFAULTS.font.family}`;
          const lbl = labels[i] || '';
          ctx.fillText(lbl.length > 12 ? lbl.slice(0,11)+'…' : lbl, x + barW / 2, padT + chartH + 4);
        }
      });
    });

    this._chartBounds = { padL, padR, padT, padB, chartW, chartH, maxVal, isH, grpW, barW, gap };
  }

  _roundRect(ctx, x, y, w, h, r, fill) {
    if (w <= 0 || h <= 0) return;
    r = Math.min(r, w/2, h/2);
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
    ctx.fillStyle = fill;
    ctx.fill();
  }

  _drawLine(W, H) {
    const ctx    = this.ctx;
    const labels = this._getLabels();
    const padL = 50, padR = 20, padT = 20, padB = 60;
    const chartW = W - padL - padR;
    const chartH = H - padT - padB;

    let maxVal = 0;
    this._getDatasets().forEach(ds => ds.data.forEach(v => { if (v > maxVal) maxVal = v; }));
    maxVal = maxVal || 1;
    const n = labels.length;

    // Grid
    ctx.strokeStyle = '#e4eae6'; ctx.lineWidth = 1;
    for (let s = 0; s <= 5; s++) {
      const val = (maxVal / 5) * s;
      const y   = padT + chartH - (val / maxVal) * chartH;
      ctx.beginPath(); ctx.moveTo(padL, y); ctx.lineTo(padL + chartW, y); ctx.stroke();
      ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
      ctx.font = `11px ${DEFAULTS.font.family}`;
      ctx.fillText(Math.round(val), padL - 6, y);
    }

    // Lines
    this._getDatasets().forEach((ds, di) => {
      const color  = Array.isArray(ds.borderColor) ? ds.borderColor[0] : ds.borderColor || '#2ecc71';
      const fillC  = ds.backgroundColor || hexToRgba(color.replace('#','').length===6?color:'#2ecc71', 0.15);
      const pts    = ds.data.map((v, i) => ({
        x: padL + (n > 1 ? (i / (n - 1)) * chartW : chartW / 2),
        y: padT + chartH - (v / maxVal) * chartH
      }));

      // Fill area
      if (ds.fill && pts.length) {
        ctx.beginPath();
        ctx.moveTo(pts[0].x, padT + chartH);
        if (ds.tension) {
          pts.forEach((p, i) => {
            if (i === 0) { ctx.lineTo(p.x, p.y); return; }
            const cp = pts[i - 1];
            const mx = (cp.x + p.x) / 2;
            ctx.bezierCurveTo(mx, cp.y, mx, p.y, p.x, p.y);
          });
        } else {
          pts.forEach(p => ctx.lineTo(p.x, p.y));
        }
        ctx.lineTo(pts[pts.length-1].x, padT + chartH);
        ctx.closePath();
        ctx.fillStyle = typeof fillC === 'string' ? fillC : hexToRgba('#2ecc71', 0.1);
        ctx.fill();
      }

      // Line
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = 2.5;
      if (ds.tension && pts.length) {
        ctx.moveTo(pts[0].x, pts[0].y);
        pts.forEach((p, i) => {
          if (i === 0) return;
          const cp = pts[i - 1];
          const mx = (cp.x + p.x) / 2;
          ctx.bezierCurveTo(mx, cp.y, mx, p.y, p.x, p.y);
        });
      } else {
        pts.forEach((p, i) => i === 0 ? ctx.moveTo(p.x, p.y) : ctx.lineTo(p.x, p.y));
      }
      ctx.stroke();

      // Points
      const pr = ds.pointRadius || 4;
      pts.forEach(p => {
        ctx.beginPath(); ctx.arc(p.x, p.y, pr, 0, Math.PI * 2);
        ctx.fillStyle = ds.pointBackgroundColor || color; ctx.fill();
        ctx.strokeStyle = '#fff'; ctx.lineWidth = 1.5; ctx.stroke();
      });

      // X labels
      ctx.fillStyle = DEFAULTS.color; ctx.textAlign = 'center'; ctx.textBaseline = 'top';
      ctx.font = `10px ${DEFAULTS.font.family}`;
      labels.forEach((lbl, i) => {
        const x = padL + (n > 1 ? (i / (n - 1)) * chartW : chartW / 2);
        ctx.fillText(lbl, x, padT + chartH + 6);
      });
    });
  }

  _drawPie(W, H, doughnut) {
    const ctx      = this.ctx;
    const ds       = this._getDS(0);
    const data     = ds.data || [];
    const colors   = ds.backgroundColor || [];
    const total    = data.reduce((a, b) => a + b, 0) || 1;
    const legH     = this._legendHeight(W);
    const cx       = W / 2;
    const cy       = (H - legH) / 2;
    const r        = Math.min(cx, cy) * 0.82;
    const ir       = doughnut ? r * 0.55 : 0;
    let start      = -Math.PI / 2;
    const bw       = ds.borderWidth || 2;

    data.forEach((val, i) => {
      const slice = (val / total) * Math.PI * 2;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.arc(cx, cy, r, start, start + slice);
      ctx.closePath();
      ctx.fillStyle = getColor(colors, i);
      ctx.fill();
      if (bw) { ctx.strokeStyle = ds.borderColor || '#fff'; ctx.lineWidth = bw; ctx.stroke(); }

      // Slice label
      if (val > 0) {
        const mid = start + slice / 2;
        const lr  = (r + ir) / 2 + (doughnut ? 0 : r * 0.2);
        const lx  = cx + Math.cos(mid) * lr * 0.75;
        const ly  = cy + Math.sin(mid) * lr * 0.75;
        ctx.fillStyle   = '#fff';
        ctx.font        = `bold 11px ${DEFAULTS.font.family}`;
        ctx.textAlign   = 'center';
        ctx.textBaseline= 'middle';
        const pct = Math.round((val / total) * 100);
        if (pct >= 8) ctx.fillText(pct + '%', lx, ly);
      }
      start += slice;
    });

    // Doughnut hole
    if (doughnut) {
      ctx.beginPath(); ctx.arc(cx, cy, ir, 0, Math.PI * 2);
      ctx.fillStyle = '#ffffff'; ctx.fill();
    }

    this._pieBounds = { cx, cy, r, total, data, colors };
  }

  _drawPolar(W, H) {
    const ctx    = this.ctx;
    const ds     = this._getDS(0);
    const data   = ds.data || [];
    const colors = ds.backgroundColor || [];
    const labels = this._getLabels();
    const legH   = this._legendHeight(W);
    const cx     = W / 2;
    const cy     = (H - legH) / 2;
    const r      = Math.min(cx, cy) * 0.82;
    const maxVal = Math.max(...data) || 1;
    const step   = (Math.PI * 2) / (data.length || 1);

    data.forEach((val, i) => {
      const angle = i * step - Math.PI / 2;
      const len   = (val / maxVal) * r;
      ctx.beginPath();
      ctx.moveTo(cx, cy);
      ctx.arc(cx, cy, len, angle, angle + step);
      ctx.closePath();
      const c = getColor(colors, i);
      ctx.fillStyle   = typeof c === 'string' ? c.replace(/,[\d.]+\)/, ',0.8)') : c;
      ctx.fill();
      ctx.strokeStyle = '#fff'; ctx.lineWidth = 2; ctx.stroke();
    });
    // Grid circles
    ctx.strokeStyle = 'rgba(0,0,0,0.08)'; ctx.lineWidth = 1;
    [0.25, 0.5, 0.75, 1].forEach(f => {
      ctx.beginPath(); ctx.arc(cx, cy, r * f, 0, Math.PI * 2); ctx.stroke();
    });
  }

  _legendHeight(W) {
    const legPos = this.options?.plugins?.legend?.position;
    return (legPos === 'bottom' || !legPos) ? 50 : 0;
  }

  _drawLegend(W, H) {
    const legendOpts = this.options?.plugins?.legend;
    if (legendOpts?.display === false) return;

    const labels   = this._getLabels();
    const datasets = this._getDatasets();
    const pos      = legendOpts?.position || 'bottom';
    const ctx      = this.ctx;
    const isBottom = pos === 'bottom';

    let items = [];
    if (['doughnut','pie','polarArea'].includes(this.type)) {
      const ds = this._getDS(0);
      labels.forEach((lbl, i) => items.push({ label: lbl, color: getColor(ds.backgroundColor, i) }));
    } else {
      datasets.forEach(ds => items.push({ label: ds.label || '', color: Array.isArray(ds.backgroundColor) ? ds.backgroundColor[0] : (ds.borderColor || ds.backgroundColor || '#ccc') }));
    }

    if (!items.length) return;

    ctx.font = `12px ${DEFAULTS.font.family}`;
    ctx.textBaseline = 'middle';

    const itemW = 14, gap = 6, vpad = 8;
    const rows  = [];
    let row     = [], rowW = 0;
    items.forEach(item => {
      const tw = ctx.measureText(item.label).width + itemW + gap + 16;
      if (rowW + tw > W - 20 && row.length) { rows.push(row); row = []; rowW = 0; }
      row.push(item); rowW += tw;
    });
    if (row.length) rows.push(row);

    const totalH = rows.length * 22 + vpad;
    const startY = isBottom ? H - totalH : vpad;

    rows.forEach((row, ri) => {
      const rowW  = row.reduce((s, it) => s + ctx.measureText(it.label).width + itemW + gap + 16, 0);
      let   x     = (W - rowW) / 2;
      const y     = startY + ri * 22 + 11;

      row.forEach(item => {
        ctx.fillStyle = item.color;
        ctx.fillRect(x, y - 5, itemW, 10);
        ctx.fillStyle = DEFAULTS.color;
        ctx.fillText(item.label, x + itemW + gap, y);
        x += ctx.measureText(item.label).width + itemW + gap + 16;
      });
    });
  }

  _setupTooltip() {
    const canvas  = this.canvas;
    const tip     = this._tip = this._tip || document.createElement('div');
    const tipStyle= 'position:fixed;background:#0b2e25;color:#fff;padding:8px 12px;border-radius:8px;font-size:12px;pointer-events:none;z-index:9999;display:none;line-height:1.5;box-shadow:0 4px 12px rgba(0,0,0,.25)';
    tip.style.cssText = tipStyle;
    if (!tip.parentNode) document.body.appendChild(tip);

    const self = this;
    canvas.onmousemove = function(e) {
      const rect = canvas.getBoundingClientRect();
      const mx   = e.clientX - rect.left;
      const my   = e.clientY - rect.top;
      const info = self._hitTest(mx, my);
      if (info) {
        tip.innerHTML = `<strong>${info.label}</strong><br>${info.value}`;
        tip.style.display = 'block';
        tip.style.left    = (e.clientX + 12) + 'px';
        tip.style.top     = (e.clientY - 30) + 'px';
      } else {
        tip.style.display = 'none';
      }
    };
    canvas.onmouseleave = () => tip.style.display = 'none';
  }

  _hitTest(mx, my) {
    const labels = this._getLabels();
    const b      = this._chartBounds;
    const pb     = this._pieBounds;

    if (pb && ['doughnut','pie'].includes(this.type)) {
      const dx  = mx - pb.cx, dy = my - pb.cy;
      const dist= Math.sqrt(dx*dx + dy*dy);
      if (dist <= pb.r) {
        let angle = Math.atan2(dy, dx) + Math.PI / 2;
        if (angle < 0) angle += Math.PI * 2;
        let start = 0;
        for (let i = 0; i < pb.data.length; i++) {
          const slice = (pb.data[i] / pb.total) * Math.PI * 2;
          if (angle >= start && angle < start + slice) {
            return { label: labels[i] || '', value: pb.data[i] };
          }
          start += slice;
        }
      }
      return null;
    }

    if (b && this.type === 'bar') {
      const ds   = this._getDatasets();
      const n    = labels.length;
      for (let i = 0; i < n; i++) {
        for (let di = 0; di < ds.length; di++) {
          if (b.isH) {
            const y    = b.padT + i * b.grpW + b.gap + di * b.barW;
            const bLen = (ds[di].data[i] / b.maxVal) * b.chartW;
            if (my >= y && my <= y + b.barW && mx >= b.padL && mx <= b.padL + bLen) {
              return { label: labels[i], value: ds[di].data[i] };
            }
          } else {
            const x    = b.padL + i * b.grpW + b.gap + di * b.barW;
            const bLen = (ds[di].data[i] / b.maxVal) * b.chartH;
            const y    = b.padT + b.chartH - bLen;
            if (mx >= x && mx <= x + b.barW && my >= y && my <= b.padT + b.chartH) {
              return { label: labels[i], value: ds[di].data[i] };
            }
          }
        }
      }
    }
    return null;
  }

  destroy() {
    if (this._resizeObs) this._resizeObs.disconnect();
    if (this._tip && this._tip.parentNode) this._tip.parentNode.removeChild(this._tip);
    this.canvas.onmousemove = null;
    this.canvas.onmouseleave = null;
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  }

  update() { this._resize(); this._draw(); }
}

// Static defaults
Chart.defaults = DEFAULTS;

// Register (no-op for compatibility)
Chart.register = function() {};

global.Chart = Chart;
})(typeof window !== 'undefined' ? window : this);
